  const colors: Record<Product["status"], string> = {
    active: "#16a34a",
    inactive: "#ca8a04",
    discontinued: "#dc2626",
  };
  return (
    <span
      style={{
        display: "inline-block",
        padding: "2px 8px",
        borderRadius: "999px",
        fontSize: "0.75rem",
        fontWeight: 600,
        color: "#fff",
        backgroundColor: colors[status],
      }}
    >
      {status}
    </span>
  );
}

// ── Page ─────────────────────────────────────────────────────────────

